import { useState, useEffect } from 'react';
import { AdminService } from '../../../services/api';
import { Image as ImageIcon, Link as LinkIcon, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtworkForm = () => {
  const [formData, setFormData] = useState({
    Artwork_ID: '',
    Title_En: '',
    Title_Ar: '',
    Artist_ID: '', // This links to the Artist
    Year: '',
    Medium: '',
  });

  const [artists, setArtists] = useState([]); // To populate a dropdown

  useEffect(() => {
    AdminService.getAllArtists().then(res => setArtists(res.data));
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await AdminService.upsertArtwork(formData);
      toast.success("Artwork Registered in Gallery");
    } catch (err) {
      toast.error("Upload Failed");
    }
  };

  return (
    <div className="max-w-4xl bg-white dark:bg-[#0a0a0a] p-12 rounded-[3rem] border dark:border-white/5">
      <h2 className="text-3xl font-black uppercase italic mb-8">Forge <span className="text-primary">Artwork</span></h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-2 gap-4">
          <input 
            placeholder="Artwork ID" 
            className="w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 font-bold outline-none border border-transparent focus:border-primary"
            onChange={e => setFormData({...formData, Artwork_ID: e.target.value})}
          />
          {/* ARTIST DROPDOWN */}
          <select 
            className="w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 font-black uppercase text-[10px] outline-none"
            onChange={e => setFormData({...formData, Artist_ID: e.target.value})}
          >
            <option>Select Artist</option>
            {artists.map((a: any) => <option key={a.Artist_ID} value={a.Artist_ID}>{a.Full_Name}</option>)}
          </select>
        </div>
        
        <input placeholder="Title (English)" className="w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 font-bold" onChange={e => setFormData({...formData, Title_En: e.target.value})} />
        <input placeholder="العنوان بالعربي" dir="rtl" className="w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 font-bold" onChange={e => setFormData({...formData, Title_Ar: e.target.value})} />
        
        <button className="w-full py-6 bg-black text-white rounded-2xl font-black uppercase tracking-widest hover:bg-primary transition-all">
          Deploy to Gallery
        </button>
      </form>
    </div>
  );
};
